const fs = require('fs');
const path = require('path');
const axios = require('axios');
const TG = $env.TG_TOKEN;
if (!TG) return [{ json: { error: 'TG_TOKEN not set' } }];
const WHISPER = 'http://host.docker.internal:9000/transcribe';
const OFFSET_FILE = '/vault/.cache/tg_offset.txt';
fs.mkdirSync('/vault/.cache', { recursive: true });
fs.mkdirSync('/vault/inbox/audio', { recursive: true });
fs.mkdirSync('/vault/inbox/transcripts', { recursive: true });
let offset = 0;
try { offset = parseInt(fs.readFileSync(OFFSET_FILE, 'utf8'), 10) || 0; } catch (_) {}
const pad = (n) => String(n).padStart(2, '0');
const fmtTs = (d) => d.getFullYear() + pad(d.getMonth()+1) + pad(d.getDate()) + '-' + pad(d.getHours()) + pad(d.getMinutes()) + pad(d.getSeconds());
const api = 'https://api.telegram.org/bot' + TG;
const updRes = (await axios.get(api + '/getUpdates', { params: { offset: offset, timeout: 0, allowed_updates: JSON.stringify(['message']) }, timeout: 15000 })).data;
if (!updRes.ok) return [{ json: { error: 'getUpdates failed', detail: updRes } }];
const out = [];
let maxId = offset - 1;
for (const u of updRes.result) {
  if (u.update_id > maxId) maxId = u.update_id;
  const m = u.message;
  if (!m) continue;
  const voice = m.voice || m.audio;
  if (!voice) { out.push({ skipped: true, message_id: m.message_id, text: m.text }); continue; }
  const f = (await axios.get(api + '/getFile', { params: { file_id: voice.file_id }, timeout: 15000 })).data;
  if (!f.ok) { out.push({ error: 'getFile failed', detail: f }); continue; }
  const tgPath = f.result.file_path;
  const dl = await axios.get('https://api.telegram.org/file/bot' + TG + '/' + tgPath, { responseType: 'arraybuffer', timeout: 60000 });
  const buf = Buffer.from(dl.data);
  const ext = (tgPath.split('.').pop() || 'ogg').toLowerCase();
  const ts = new Date(m.date * 1000);
  const audioPath = '/vault/inbox/audio/' + fmtTs(ts) + '-' + m.message_id + '.' + ext;
  fs.writeFileSync(audioPath, buf);
  let text = '';
  let wErr = null;
  try {
    const wRes = await axios.post(WHISPER, { path: audioPath, language: 'zh' }, { timeout: 600000 });
    text = (wRes.data && wRes.data.text) ? String(wRes.data.text).trim() : '';
  } catch (e) { wErr = (e.response && e.response.data) ? e.response.data : String(e); }
  const mdPath = '/vault/inbox/transcripts/' + fmtTs(ts) + '-' + m.message_id + '.md';
  const isoTs = ts.toISOString();
  const md = '---\ncreated: ' + isoTs + '\ntype: transcript\nsource: telegram\nmessage_id: ' + m.message_id + '\nduration: ' + (voice.duration || 0) + '\naudio: ' + audioPath + '\n---\n\n# ' + isoTs.slice(0,16).replace('T',' ') + '\n\n' + text + '\n';
  fs.writeFileSync(mdPath, md, 'utf8');
  const fname = path.basename(mdPath);
  const preview = text.length > 300 ? text.slice(0, 300) + '...' : text;
  const reply = wErr ? ('[ERR] whisper failed: ' + JSON.stringify(wErr).slice(0, 500)) : ('[OK] saved ' + fname + '\n\n' + preview);
  try { await axios.post(api + '/sendMessage', { chat_id: m.chat.id, text: reply, reply_to_message_id: m.message_id }, { timeout: 15000 }); } catch (_) {}
  out.push({ ok: !wErr, audio: audioPath, md: mdPath, chars: text.length, wErr });
}
if (maxId >= offset) fs.writeFileSync(OFFSET_FILE, String(maxId + 1), 'utf8');
return [{ json: { processed: out.length, offset_to: maxId + 1, items: out } }];
